import{_ as s,c as i,o as t,a2 as a}from"./chunks/framework.CIiVzG-O.js";const g=JSON.parse('{"title":"macOS Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/permissions.md","filePath":"guide/permissions.md","lastUpdated":1783607180000}'),n={name:"guide/permissions.md"};function o(r,e,l,p,c,d){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="macos-permissions" tabindex="-1">macOS Permissions <a class="header-anchor" href="#macos-permissions" aria-label="Permalink to &quot;macOS Permissions&quot;">​</a></h1><p>NueZip may request a few macOS permissions to provide the best experience. This page explains what each permission is for and how to manage them.</p><h2 id="files-and-folders" tabindex="-1">Files and Folders <a class="header-anchor" href="#files-and-folders" aria-label="Permalink to &quot;Files and Folders&quot;">​</a></h2><p>To access archives anywhere on your system, NueZip needs file access permission.</p><p><strong>What it&#39;s used for</strong>: Reading archive files, extracting contents, and creating new archives.</p><p><strong>Manage</strong>: System Settings → <strong>Privacy &amp; Security</strong> → <strong>Files and Folders</strong></p><p>Grant access when prompted during first launch. You can manage or revoke access at any time.</p><h2 id="finder-extension" tabindex="-1">Finder Extension <a class="header-anchor" href="#finder-extension" aria-label="Permalink to &quot;Finder Extension&quot;">​</a></h2><p>NueZip includes a Finder extension that adds right-click context menu options.</p><p><strong>What it&#39;s used for</strong>: Right-click archive files to extract, compress, or open with NueZip directly from Finder.</p><p><strong>Enable</strong>: System Settings → <strong>Privacy &amp; Security</strong> → <strong>Extensions</strong> → <strong>Finder Extensions</strong> → Enable <strong>NueZip</strong></p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>NueZip may show notifications for long-running operations (batch extraction, large archive compression).</p><p><strong>What it&#39;s used for</strong>: Alerting you when a background operation completes.</p><p><strong>Manage</strong>: System Settings → <strong>Notifications</strong> → <strong>NueZip</strong></p><h2 id="full-disk-access-optional" tabindex="-1">Full Disk Access (Optional) <a class="header-anchor" href="#full-disk-access-optional" aria-label="Permalink to &quot;Full Disk Access (Optional)&quot;">​</a></h2><p>For extracting archives to system-protected locations, NueZip may request Full Disk Access.</p><p><strong>What it&#39;s used for</strong>: Writing extracted files to locations outside your user folder.</p><p><strong>Manage</strong>: System Settings → <strong>Privacy &amp; Security</strong> → <strong>Full Disk Access</strong></p><p>This permission is optional and only needed if you work with system-wide locations.</p><h2 id="resetting-a-permission-with-terminal" tabindex="-1">Resetting a Permission with Terminal <a class="header-anchor" href="#resetting-a-permission-with-terminal" aria-label="Permalink to &quot;Resetting a Permission with Terminal&quot;">​</a></h2><p>If a permission dialog was dismissed or the state is inconsistent, you can reset macOS permission prompts using <code>tccutil</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Reset permissions for NueZip</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> All</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> com.nuezip.app</span></span></code></pre></div><p>After running <code>tccutil</code>, restart the app and trigger the feature again to be reprompted.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li>If pets don&#39;t appear on reminders, check <strong>Notifications</strong> permission is granted.</li><li>If purchased pets aren&#39;t downloading, check <strong>Files and Folders</strong> permission.</li><li>After changing permissions, always quit and reopen PetReminder for changes to take effect.</li></ul><p>For more help, visit the <a href="./troubleshooting.html">Troubleshooting guide</a>.</p>`,27)])])}const m=s(n,[["render",o]]);export{g as __pageData,m as default};
